UPDATE public.questions SET
  stimulus_text = 'In her essay on urban soundscapes, writer 3 contends that city planners should classify chronic noise pollution as a public-health hazard, citing longitudinal studies linking traffic noise to elevated cortisol, fragmented sleep, and diminished cognitive performance among residents. She describes neighborhoods where sirens, construction, and highway hum overlap for eighteen hours daily, leaving inhabitants with interrupted rest even when particulate counts meet regulatory thresholds. Community interviews quoted in the essay repeatedly mention difficulty concentrating at work, heightened irritability at home, and reluctance to open windows despite heat. The writer contrasts cosmetic beautification projects—planters, murals, and repainted facades—with measurable acoustic interventions such as berms, low-noise pavement, delivery-time restrictions, and targeted speed reductions. She acknowledges that absolute silence is unattainable in dense cities, yet insists that reducing predictable high-decibel spikes could yield health benefits comparable to modest gains in accessible green space. The essay concludes that sound belongs in municipal planning budgets alongside air quality and light pollution.',
  question_text = 'According to the passage, which statement is most strongly supported by the text?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"The passage establishes that sustained parrotfish grazing suppresses macroalgal proliferation, linking herbivory to measurable recruitment outcomes across monitored sites.","is_correct":true,"explanation":"The passage explicitly ties sustained parrotfish grazing suppresses macroalgal proliferation to reef health through comparative site data rather than speculative claims."},{"id":"B","text":"Once macroalgae dominate a reef, coral larvae can never attach to any surface regardless of subsequent grazing pressure.","is_correct":false,"explanation":"The passage describes recovery mechanisms and does not claim permanent loss once algae appear; grazing can restore bare rock."},{"id":"C","text":"The authors dismiss empirical field surveys in favor of anecdotal reports from recreational divers who visit the sites.","is_correct":false,"explanation":"The passage cites transects, chemical assays, and follow-up surveys—methods inconsistent with rejecting scientific inquiry."},{"id":"D","text":"Temperature and salinity fluctuations alone explain every decline in coral recruitment documented in the longitudinal study.","is_correct":false,"explanation":"The passage states recruitment declined even when temperature and salinity remained stable, implicating grazing rather than water chemistry alone."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The passage explains how grazing intensity, algal proliferation, and coral settlement interact to shape reef recovery after disturbance. The passage anchors the correct choice in language such as "In her essay on urban soundscapes, writer 3 contends that city planners should classify chronic nois…", which eliminates options that contradict or overreach that evidence. Choice A is correct because it aligns with the textual logic: x. Each incorrect option either contradicts an explicit detail, imports information absent from the stimulus, or answers a different question than the stem asks. On hard Digital SAT items, the best answer synthesizes multiple sentences rather than matching a single keyword in isolation.',
  difficulty = 'hard',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"CID","domain_id":"information","opensat_index":39,"opensat_domain":"Information and Ideas","opensat_raw_id":"random_id_12","english_content_v2":true,"opensat_difficulty":"Hard","difficulty_reclassified_at":"2026-06-12T20:24:49.070Z","difficulty_reclassified_to":"medium","english_content_upgraded_at":"2026-06-12T20:01:56.897Z","difficulty_reclassified_from":"hard","difficulty_reclassified_reason":"calibration_shift_down_v1","english_content_upgrade_method":"upgrade-english-content.mjs","hard_content_v2":true,"hard_content_upgraded_at":"2026-06-12T20:29:31.372Z","hard_content_upgrade_method":"generate-hard-english.mjs","prior_difficulty":"medium"}'::jsonb,
  updated_at = now()
WHERE id = 'b641c0d2-6b7b-425a-8e4c-60a00b54ff04';
UPDATE public.questions SET
  stimulus_text = 'Economists analyzing market disruption 4 observed that independent retailers adapted more nimbly than national chains when supply chains stalled, partly because they could reorder from local wholesalers within days rather than awaiting centralized distribution. While big-box stores waited for corporate approval to alter procurement contracts, corner shops consulted handwritten contact lists and shifted product mix toward shelf-stable goods and services independent of overseas shipping. The economists interviewed owners who renegotiated credit terms with regional suppliers and temporarily expanded delivery radius to retain customers. National chains, bound to uniform pricing algorithms and national vendor agreements, could not pivot without multi-week executive review cycles. The study does not claim small stores universally outperform conglomerates; rather, it demonstrates that organizational flexibility and embedded local relationships became decisive when long-distance logistics failed abruptly. Readers should infer that scale economies can become liabilities during sudden disruptions that reward improvisation over standardized efficiency.',
  question_text = 'Which choice best states the central claim the author develops throughout the passage?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"Protecting herbivorous fish is essential for reef recovery because grazing controls algae and enables coral settlement on bare substrate.","is_correct":true,"explanation":"The passage develops a causal chain connecting grazing, algae control, and coral settlement across multiple paragraphs of field evidence."},{"id":"B","text":"Once macroalgae dominate a reef, coral larvae can never attach to any surface regardless of subsequent grazing pressure.","is_correct":false,"explanation":"The passage describes recovery mechanisms and does not claim permanent loss once algae appear; grazing can restore bare rock."},{"id":"C","text":"The authors dismiss empirical field surveys in favor of anecdotal reports from recreational divers who visit the sites.","is_correct":false,"explanation":"The passage cites transects, chemical assays, and follow-up surveys—methods inconsistent with rejecting scientific inquiry."},{"id":"D","text":"Temperature and salinity fluctuations alone explain every decline in coral recruitment documented in the longitudinal study.","is_correct":false,"explanation":"The passage states recruitment declined even when temperature and salinity remained stable, implicating grazing rather than water chemistry alone."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The passage explains how grazing intensity, algal proliferation, and coral settlement interact to shape reef recovery after disturbance. The passage anchors the correct choice in language such as "Economists analyzing market disruption 4 observed that independent retailers adapted more nimbly tha…", which eliminates options that contradict or overreach that evidence. Choice A is correct because it aligns with the textual logic: x. Each incorrect option either contradicts an explicit detail, imports information absent from the stimulus, or answers a different question than the stem asks. On hard Digital SAT items, the best answer synthesizes multiple sentences rather than matching a single keyword in isolation.',
  difficulty = 'hard',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"CID","domain_id":"information","opensat_index":71,"opensat_domain":"Information and Ideas","opensat_raw_id":"random_id_8","english_content_v2":true,"opensat_difficulty":"Hard","difficulty_reclassified_at":"2026-06-12T20:24:49.070Z","difficulty_reclassified_to":"medium","english_content_upgraded_at":"2026-06-12T20:01:56.897Z","difficulty_reclassified_from":"hard","difficulty_reclassified_reason":"calibration_shift_down_v1","english_content_upgrade_method":"upgrade-english-content.mjs","hard_content_v2":true,"hard_content_upgraded_at":"2026-06-12T20:29:31.372Z","hard_content_upgrade_method":"generate-hard-english.mjs","prior_difficulty":"medium"}'::jsonb,
